from flask import Flask, request, jsonify
import json
import os
import time

app = Flask(__name__)
CACHE_DIR = 'cache'
if not os.path.exists(CACHE_DIR):
    os.makedirs(CACHE_DIR)

def cache_key(endpoint, args):
    return f"{endpoint}_{','.join(str(a) for a in args)}"

def load_cache(key):
    file_path = os.path.join(CACHE_DIR, key)
    if os.path.exists(file_path):
        with open(file_path, 'r') as f:
            data = json.load(f)
            if 'timestamp' in data and time.time() - data['timestamp'] < 3600:  # Cache expires after 1 hour
                return data['data']
    return None

def save_cache(key, data):
    file_path = os.path.join(CACHE_DIR, key)
    with open(file_path, 'w') as f:
        json.dump({'timestamp': time.time(), 'data': data}, f)

@app.route('/api/expensive', methods=['GET'])
def expensive_api():
    args = request.args
    cache_key_value = cache_key('expensive', args)
    cached_data = load_cache(cache_key_value)
    
    if cached_data is not None:
        return jsonify(cached_data), 200
    
    # Simulate an expensive API call
    expensive_result = {
        'data': [1, 2, 3],
        'metadata': {'status': 'success'}
    }
    
    save_cache(cache_key_value, expensive_result)
    return jsonify(expensive_result), 200

if __name__ == '__main__':
    app.run(debug=True)